import type { LucideIcon } from "lucide-react";
import { KpiPill } from "@/components/ui/kpi-pill";
import { StatFigure } from "@/components/ui/stat-figure";
import { cn } from "@/lib/utils";

export interface WelcomeKpiItem {
  label: string;
  pct: number;
  variant: "dark" | "yellow" | "striped" | "outline";
}

export interface WelcomeStatItem {
  icon: LucideIcon;
  value: string;
  label: string;
}

export interface WelcomeKpiProps {
  title: string;
  kpis: WelcomeKpiItem[];
  stats: WelcomeStatItem[];
  className?: string;
}

function WelcomeKpi({ title, kpis, stats, className }: WelcomeKpiProps) {
  return (
    <section className={cn("space-y-6 pt-2 sm:pt-4", className)}>
      <h1 className="font-display text-4xl font-black tracking-tight text-neutral-900 sm:text-5xl md:text-6xl">
        {title}
      </h1>

      <div className="flex flex-wrap items-end justify-between gap-8">
        <div className="flex flex-wrap items-end gap-4 sm:gap-6">
          {kpis.map((kpi) => (
            <div key={kpi.label} className="flex flex-col gap-2">
              <span className="text-xs font-medium text-neutral-500">{kpi.label}</span>
              <KpiPill pct={kpi.pct} variant={kpi.variant} />
            </div>
          ))}
        </div>

        <div className="flex flex-wrap items-end gap-6 sm:gap-8">
          {stats.map((stat) => (
            <StatFigure key={stat.label} icon={stat.icon} value={stat.value} label={stat.label} />
          ))}
        </div>
      </div>
    </section>
  );
}

export { WelcomeKpi };

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const kpiPillVariants = cva(
  "relative inline-flex items-center justify-center overflow-hidden rounded-full px-6 py-2.5 text-sm font-semibold min-w-[88px]",
  {
    variants: {
      variant: {
        dark: "bg-neutral-200 text-white",
        yellow: "bg-brand-yellow-lt text-neutral-900",
        striped: "min-w-[280px] border border-neutral-300 bg-white text-neutral-600",
        outline: "border border-neutral-300 bg-transparent text-neutral-600",
      },
    },
    defaultVariants: {
      variant: "dark",
    },
  },
);

export interface KpiPillProps
  extends React.HTMLAttributes<HTMLSpanElement>, VariantProps<typeof kpiPillVariants> {
  pct: number;
}

function KpiPill({ className, variant, pct, ...props }: KpiPillProps) {
  const label = `${pct}%`;

  if (variant === "striped") {
    return (
      <span
        className={cn(kpiPillVariants({ variant }), className)}
        aria-label={`${pct}% — Project time`}
        {...props}
      >
        <span
          className="absolute inset-y-0 left-0 animate-kpi-fill"
          style={{
            width: `${pct}%`,
            backgroundImage: "repeating-linear-gradient(135deg, #fff 0 8px, #e8e8e8 8px 10px)",
          }}
        />
        <span className="relative">{label}</span>
      </span>
    );
  }

  const fillBg =
    variant === "dark"
      ? "bg-neutral-900"
      : variant === "yellow"
        ? "bg-primary"
        : "bg-neutral-200";

  return (
    <span className={cn(kpiPillVariants({ variant }), className)} aria-label={label} {...props}>
      <span
        className={cn("absolute inset-y-0 left-0 animate-kpi-fill", fillBg)}
        style={{ width: `${pct}%` }}
      />
      <span className="relative">{label}</span>
    </span>
  );
}

export { KpiPill, kpiPillVariants };

import * as React from "react";
import type { LucideIcon } from "lucide-react";

import { cn } from "@/lib/utils";

export interface StatFigureProps {
  icon: LucideIcon;
  value: string;
  label: string;
  className?: string;
}

function StatFigure({ icon: Icon, value, label, className }: StatFigureProps) {
  return (
    <div className={cn("flex flex-col items-start", className)}>
      <div className="flex items-center gap-3">
        <span className="flex h-9 w-9 items-center justify-center rounded-full border border-neutral-300">
          <Icon className="h-4 w-4 text-neutral-600" strokeWidth={1.5} />
        </span>
        <span className="text-4xl font-bold tracking-tight text-neutral-900 sm:text-5xl">{value}</span>
      </div>
      <span className="ml-12 text-xs font-medium text-muted-foreground">{label}</span>
    </div>
  );
}

export { StatFigure };
